import { useEffect, useState } from "react";
import { useNavigate } from "react-router-dom";

import DeanLayout from "../../layouts/DeanLayout";

import {
  getHodSubmissions,
  downloadHodPDF,
  approveSubmission,
  rejectSubmission
} from "../../api/deanApi";

import schoolsDepartments
from "../../data/schoolsDepartments";

import { useAuth }
from "../../context/AuthContext";

function HodReview() {

  const navigate = useNavigate();

  const { user } = useAuth();

  const [loading, setLoading] =
    useState(true);

  const [submissions, setSubmissions] =
    useState([]);

  const [selectedDepartment, setSelectedDepartment] =
    useState(
      sessionStorage.getItem(
        "deanHodDepartment"
      ) || ""
    );
const [activeTab, setActiveTab] =
  useState("Pending Dean Review");
  const [remarks, setRemarks] =
  useState("");

const [selectedSubmission, setSelectedSubmission] =
  useState(null);

  useEffect(() => {

    loadSubmissions();

  }, []);

  const loadSubmissions = async () => {

  try {

    const res =
      await getHodSubmissions(
        activeTab,
        selectedDepartment
      );

    setSubmissions(
      res.data.submissions || []
    );

  }

  catch (err) {

    console.error(err);

  }

  finally {

    setLoading(false);

  }

};
    // ==========================
  // DEPARTMENTS OF DEAN SCHOOL
  // ==========================

  const departments =
    schoolsDepartments[
      user?.school
    ] || [];

  // ==========================
  // SAVE FILTERS
  // ==========================

  useEffect(() => {

  loadSubmissions();

}, [

  activeTab,

  selectedDepartment

]);


  // ==========================
  // FILTER SUBMISSIONS
  // ==========================

  const filteredSubmissions = submissions;

  const RejectPopup = () => (

  <div
    style={{
      position: "fixed",
      inset: 0,
      background: "rgba(0,0,0,.45)",
      display: "flex",
      justifyContent: "center",
      alignItems: "center",
      zIndex: 9999
    }}
  >

    <div
      style={{
        width: "500px",
        background: "#fff",
        borderRadius: "12px",
        padding: "30px"
      }}
    >

      <h2
        style={{
          marginBottom: "20px"
        }}
      >
        Reject Submission
      </h2>

      <textarea

        value={remarks}

        onChange={(e) =>
          setRemarks(e.target.value)
        }

        placeholder="Enter Dean Remarks"

        rows={6}

        style={{
          width: "100%",
          padding: "12px",
          borderRadius: "8px",
          resize: "vertical"
        }}

      />

      <div
        style={{
          display: "flex",
          justifyContent: "flex-end",
          gap: "15px",
          marginTop: "25px"
        }}
      >

        <button

          onClick={() => {

            setSelectedSubmission(null);

            setRemarks("");

          }}

          style={{
            padding: "10px 22px",
            border: "none",
            borderRadius: "8px",
            cursor: "pointer"
          }}

        >
          Cancel
        </button>

        <button

          onClick={handleReject}

          style={{
            background: "#dc2626",
            color: "#fff",
            border: "none",
            padding: "10px 22px",
            borderRadius: "8px",
            cursor: "pointer"
          }}

        >
          Reject
        </button>

      </div>

    </div>

  </div>

);

  // ==========================
  // PDF DOWNLOAD
  // ==========================

  const handleDownload =
    async (submission) => {

      try {

        const response =
          await downloadHodPDF(
            submission._id
          );

        const url =
          window.URL.createObjectURL(
            new Blob([response.data])
          );

        const link =
          document.createElement("a");

        link.href = url;

        link.download =
          `${submission.submittedByName}_${submission.quarter}.pdf`;

        document.body.appendChild(
          link
        );

        link.click();

        link.remove();

      }

      catch (error) {

        console.error(error);

      }

    };
    const handleApprove = async (id) => {

  try {

    await approveSubmission(
      id,
      "Approved by Dean"
    );

    loadSubmissions();

  }

  catch (err) {

    console.error(err);

    alert("Approval Failed");

  }

};
const handleReject = async () => {

  if (!selectedSubmission) return;

  if (!remarks.trim()) {

    alert("Please enter remarks");

    return;

  }

  try {

    await rejectSubmission(

      selectedSubmission,

      remarks

    );

    setRemarks("");

    setSelectedSubmission(null);

    loadSubmissions();

  }

  catch (err) {

    console.error(err);

    alert("Reject Failed");

  }

};
